    async def handle_initiate_trade(self, websocket, data: dict, player: Player):
        target_username = data.get("target_username")
        if not isinstance(target_username, str):
            await self._send_error(websocket, "Invalid target username")
            return

        target_id = self.username_to_id.get(target_username.lower())
        if target_id is None:
            await self._send_error(websocket, "Player not found")
            return

        if target_id == player.player_id:
            await self._send_error(websocket, "Cannot trade with yourself")
            return

        target_player = self.players.get(target_id)
        if target_player is None or target_id not in self.connected_clients:
            await self._send_error(websocket, "Player is not online")
            return

        async with self._trade_lock:
            if player.active_trade_id:
                await self._send_error(websocket, "You already have an active trade. Cancel it first.")
                return

            if target_player.active_trade_id:
                await self._send_error(websocket, "Target player is already in a trade")
                return

